import React, { useState, useEffect } from "react";
import SplashScreen from "./screens/SplashScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignUpScreen";
import Dashboard from "./screens/Dashboard";
import { formatCurrency } from "./helpers/helpers";

export default function App() {
  // ===== App State =====
  const [loading, setLoading] = useState(true);       // Splash screen
  const [signedIn, setSignedIn] = useState(false);    // SignIn/SignUp state
  const [currentTab, setCurrentTab] = useState("Home");

  // User & transactions
  const [user, setUser] = useState({
    name: "Faith Bode",
    email: "faith@example.com",
    joinedDate: "Jan 2026",
  });
  const [balance, setBalance] = useState(5000);
  const [transactions, setTransactions] = useState([
    { id: 1, title: "Deposit", amount: 2000, type: "deposit", date: "Jan 20, 2026" },
    { id: 2, title: "Withdrawal", amount: 500, type: "withdraw", date: "Jan 21, 2026" },
  ]);

  // Goals & loans
  const [goals, setGoals] = useState([
    { id: 1, title: "Buy Laptop", description: "Save for new laptop", targetAmount: 2000, amountSaved: 500 },
  ]);
  const [loans, setLoans] = useState([
    { id: 1, title: "Emergency Loan", amount: 1000, dueDate: "Feb 15, 2026", outstanding: 500 },
  ]);

  // Modal control
  const [modal, setModal] = useState(null);
  const [amountInput, setAmountInput] = useState("");

  // ===== Effects =====
  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  // ===== Handlers =====
  const handleSignIn = ({ email, password }) => {
    // Dummy sign-in logic
    setSignedIn(true);
  };

  const handleSignUp = ({ name, email, password }) => {
    setUser({ ...user, name, email });
    setSignedIn(true);
  };

  const handleDeposit = () => {
    if (!amountInput) return alert("Enter amount");
    const amt = parseFloat(amountInput);
    setBalance(balance + amt);
    setTransactions([{ id: Date.now(), title: "Deposit", amount: amt, type: "deposit", date: new Date().toDateString() }, ...transactions]);
    setModal(null);
    setAmountInput("");
  };

  const handleWithdraw = () => {
    if (!amountInput) return alert("Enter amount");
    const amt = parseFloat(amountInput);
    if (amt > balance) return alert("Insufficient balance");
    setBalance(balance - amt);
    setTransactions([{ id: Date.now(), title: "Withdrawal", amount: amt, type: "withdraw", date: new Date().toDateString() }, ...transactions]);
    setModal(null);
    setAmountInput("");
  };

  // ===== Render =====
  if (loading) return <SplashScreen onFinish={() => setLoading(false)} />;
  if (!signedIn) return <SignInScreen onSignIn={handleSignIn} />;

  return (
    <div className="w-screen h-screen relative">
      {/* Dashboard */}
      <Dashboard
        currentTab={currentTab}
        setCurrentTab={setCurrentTab}
        balance={balance}
        userName={user.name}
        transactions={transactions}
        goals={goals}
        loans={loans}
        user={user}
        setModal={setModal}
      />

      {/* Modal */}
      {modal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 w-11/12 max-w-sm space-y-4">
            <h2 className="text-xl font-bold">{modal === "deposit" ? "Deposit Money" : "Withdraw Money"}</h2>
            <input
              type="number"
              placeholder="Enter amount"
              value={amountInput}
              onChange={(e) => setAmountInput(e.target.value)}
              className="w-full p-3 rounded-xl border"
            />
            <div className="flex justify-end gap-3">
              <button onClick={() => setModal(null)} className="px-4 py-2 bg-gray-200 rounded-xl">Cancel</button>
              <button
                onClick={modal === "deposit" ? handleDeposit : handleWithdraw}
                className={`px-4 py-2 rounded-xl text-white ${modal === "deposit" ? "bg-emerald-600 hover:bg-emerald-700" : "bg-red-600 hover:bg-red-700"}`}
              >
                {modal === "deposit" ? "Deposit" : "Withdraw"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
